1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
3	type QuoteInput = { customer: Customer; items: Item[] };
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_BASE = 25;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	
18	export function quote(input: QuoteInput): { premium: number } {
19	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
20	
21	  let policyBase = 0;
22	  for (const item of input.items) {
23	    if (COMPONENT_TYPES.has(item.type)) {
24	      policyBase += COMPONENT_BASE;
25	    } else {
26	      policyBase += BASE_PREMIUMS[item.type];
27	    }
28	  }
29	  if (input.customer.previousContracts === 0) {
30	    policyBase = policyBase * (1 + FIRST_INSURANCE_SURCHARGE);
31	  }
32	  const total = Math.ceil(Math.round(policyBase * 100) / 100 + PROCESSING_FEE);
33	  return { premium: total };
34	}
35	
36	export function claim(_input: unknown): { payout: number } {
37	  return { payout: 0 };
38	}
